def analyze_scores(scores):
    if not scores:
        return {}
    total = sum(scores)
    average = total / len(scores)
    highest = max(scores)
    lowest = min(scores)
    passed = sum(1 for score in scores if score >= 60)
    failed = len(scores) - passed
    return {
        'average_score': average,
        'highest_score': highest,
        'lowest_score': lowest,
        'passed': passed,
        'failed': failed
    }
